{"inp":{"code":"# Compute target prices for different EV/EBITDA re-rating scenarios using implied EBITDA
shares = 293112130
net_debt = 734_834_000
implied_ebitda = 1_677_914_153
scenarios = [4.5, 5.5, 6.5]
results = {}
for m in scenarios:
    ev_target = implied_ebitda * m
    market_cap_target = ev_target - net_debt
    price_target = market_cap_target / shares
    results[m] = {
        'EV_target': ev_target,
        'MarketCap_target': market_cap_target,
        'Price_target': price_target
    }
for m, v in results.items():
    print(f"EV/EBITDA = {m}: EV_target = R$ {v['EV_target']:,.0f}, MarketCap_target = R$ {v['MarketCap_target']:,.0f}, Price_target = R$ {v['Price_target']:.2f}")
"} }
